function a(n){return Math.round(n*100)/100}function c(n,t,e=0){let o=n.price*t,i=1-Math.max(0,Math.min(100,e))/100;return a(o*i)}function u(n,t){if(t.companionBookId!=null)return n.find(e=>e.id===t.companionBookId)}function s(n){return`${n.bookType==="PAQUETE"?"**":"*"} ${n.title}`}function l(n,t){if(!n||n.bookType!=="PAQUETE"||!n.companionBookTitle)return null;let e=u(t,n),o=e?e.price.toFixed(2):"?";return`Este t\xEDtulo lleva ** en el manual de la librer\xEDa. Debes agregar \xAB${n.companionBookTitle}\xBB (B ${o}/u.) en otra l\xEDnea con **exactamente la misma cantidad** (ej. 10 y 10, nunca 10 y 6).`}function p(n,t){let e=new Map;for(let o of n)o.bookId!=null&&e.set(o.bookId,(e.get(o.bookId)??0)+Number(o.quantity));for(let o of t){if(o.bookType!=="PAQUETE"||o.companionBookId==null)continue;let i=e.get(o.id)??0;if(i===0)continue;let r=e.get(o.companionBookId)??0;if(r===0)return`\xAB${o.title}\xBB (**) requiere \xAB${o.companionBookTitle}\xBB con ${i} unidades (misma cantidad).`;if(r!==i)return`\xAB${o.companionBookTitle}\xBB debe ser ${i} uds., igual que \xAB${o.title}\xBB (tienes ${r}).`}for(let o of t){if(o.bookType!=="PAQUETE"||o.companionBookId==null||(e.get(o.companionBookId)??0)===0)continue;if((e.get(o.id)??0)===0)return`\xAB${o.companionBookTitle}\xBB va con \xAB${o.title}\xBB (**); agrega ese t\xEDtulo con la misma cantidad.`}return null}function m(n){return n?.bookType==="PAQUETE"&&n.companionBookId!=null}function d(n){return`B ${n.price.toFixed(2)} / u.`}export{c as a,u as b,s as c,l as d,p as e,m as f,d as g};
